mapper.select:
SELECT id, title, author, author_url as authorUrl, cover_img as coverImg,
       views, favorites, category, tip, created_at as createdAt, updated_at as updatedAt
FROM recipes


        category = #{category}


ORDER BY views DESC
LIMIT #{offset}, #{limit}

SELECT id, title, author, author_url as authorUrl, cover_img as coverImg,
       views, favorites, category, tip, created_at as createdAt, updated_at as updatedAt
FROM recipes WHERE id = #{id}
